+                options,
+                "hello".to_string(),
+                Vec::new(),
+                Cx::for_request(),
+            )
+            .await;
+
+            let mut saw_retry_start = false;
+            let mut saw_retry_end_success = false;
+
+            for line in out_rx.try_iter() {
+                let Ok(value) = serde_json::from_str::<Value>(&line) else {
+                    continue;
